// Config: filtros para qué posts clasificar.
// Por default: FB sin pilar desde 2026-01-01. Ajustá si querés otra red u otro rango.
return [{
  json: {
    red_social: 'FACEBOOK',
    from: '2026-01-01',
    batchSize: 50
  }
}];

// La response de PostgREST es un array. Pero el caption del scraper de FB suele estar vacío.
// Para pilar, NECESITAMOS el caption. Hacemos un fetch alternativo donde caption tampoco es NULL.
const items = $input.first().json;
if (!Array.isArray(items)) throw new Error('Response inesperada: ' + JSON.stringify(Object.keys(items)).slice(0, 200));

// Solo procesar los que tienen caption (sin caption no se puede clasificar)
const withCaption = items.filter(p => p.caption && p.caption.trim().length > 5);

const config = $('Set Config').first().json;
const batchSize = config.batchSize || 50;
const batches = [];
for (let i = 0; i < withCaption.length; i += batchSize) {
  batches.push(withCaption.slice(i, i + batchSize));
}
return batches.map(batch => ({ json: { posts: batch } }));

const posts = $json.posts || [];
const promptText = 
  'Para cada post devolve SOLO pilar (UNO de Branding/Producto/Promo/Influencer/Educacional segun el caption). NUNCA combines.\n\n' +
  'POSTS: ' + JSON.stringify(posts.map(p => ({ url: p.url, caption: (p.caption || '').slice(0, 200) }))) +
  '\n\nFormato: {"analysis":[{"url":"...","pilar":"..."}]}';
return [{
  json: {
    bodyObj: {
      model: 'gpt-4o-mini',
      temperature: 0,
      max_tokens: 8000,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: 'Clasificador de pilar. JSON valido.' },
        { role: 'user', content: promptText }
      ]
    },
    posts: posts
  }
}];

const raw = $input.first().json;
const posts = $('Build GPT Body').first().json.posts || [];
const VALID = ['Branding','Producto','Promo','Influencer','Educacional'];

let analysisArray = [];
try {
  const content = raw?.choices?.[0]?.message?.content || '';
  const parsed = JSON.parse(content);
  analysisArray = parsed.analysis || parsed;
} catch (e) {
  return [{ json: { error: 'parse failed: ' + e.message } }];
}

const pickPilar = (raw) => {
  if (!raw) return 'Branding';
  if (VALID.includes(raw)) return raw;
  const parts = (raw + '').split('/').map(s => s.trim());
  for (const p of parts) if (VALID.includes(p)) return p;
  return 'Branding';
};

const map = {};
for (const a of analysisArray) { if (a.url) map[a.url] = pickPilar(a.pilar); }

return posts
  .filter(p => map[p.url])
  .map(p => ({ json: { url: p.url, pilar: map[p.url] } }));
